import{_ as e,c as r,o as a,a5 as i}from"./chunks/framework.CgT1UzWm.js";const y=JSON.parse('{"title":"Overall Analysis — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Winners by category, performance tiers, scaling behavior, latency objectives, resource efficiency, and performance per line of code across 20 PostgreSQL REST API services.","frontmatter":{"layout":"doc","outline":[2,3],"title":"Overall Analysis — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"Winners by category, performance tiers, scaling behavior, latency objectives, resource efficiency, and performance per line of code across 20 PostgreSQL REST API services.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/analysis.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/analysis.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"Overall Analysis — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"property":"og:description","content":"Winners by category, performance tiers, scaling behavior, latency objectives, resource efficiency, and performance per line of code across 20 PostgreSQL REST API services."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Overall Analysis — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"name":"twitter:description","content":"Winners by category, performance tiers, scaling behavior, latency objectives, resource efficiency, and performance per line of code across 20 PostgreSQL REST API services."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/benchmarks-2026-07/analysis.md","filePath":"blog/benchmarks-2026-07/analysis.md","lastUpdated":1782480183000}'),s={name:"blog/benchmarks-2026-07/analysis.md"};function n(l,t,d,o,g,h){return a(),r("div",null,t[0]||(t[0]=[i('<h1 id="overall-analysis-what-760-tests-say" tabindex="-1">Overall Analysis: What 760 Tests Say <a class="header-anchor" href="#overall-analysis-what-760-tests-say" aria-label="Permalink to &quot;Overall Analysis: What 760 Tests Say&quot;">​</a></h1><p class="blog-meta"><span class="tag">Benchmark</span> · <span class="tag">Analysis</span> · <span class="tag">July 2026</span></p><p>Part of the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API Benchmark, July 2026</a> series. Methodology and fairness changes are covered in the <a href="/blog/benchmarks-2026-07/">introduction</a>; every number below is reproducible from <a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">results.csv</a>.</p><h2 id="five-findings" tabindex="-1">Five findings <a class="header-anchor" href="#five-findings" aria-label="Permalink to &quot;Five findings&quot;">​</a></h2><ol><li><strong>Go won everything that measures the HTTP server itself</strong> — all three minimal-baseline combinations, all three params combinations, most of large-payload and POST: 17 gold medals of 38 combinations, more than twice anyone else. On 25 MB of average memory.</li><li><strong>FastAPI won the headline scenario</strong> — first place in comprehensive data-type serialization (perf-test) at every concurrency level, after finishing bottom-tier in January. Nothing about FastAPI changed; its <em>deployment</em> did (1 worker → 8). The single largest ranking movement in the benchmark&#39;s history is a configuration diff.</li><li><strong>NpgsqlRest&#39;s SQL file source is the fastest zero-code path ever measured here</strong> — +33% over the routine source on small payloads, #2 and #3 in the field on perf-test, ahead of hand-written same-driver .NET code by &gt;50%. Full analysis in the <a href="/blog/benchmarks-2026-07/npgsqlrest.html">deep dive</a>.</li><li><strong>Sibling frameworks are statistically identical.</strong> Actix vs Axum: +0.8%. Fastify vs Express: −1.4%. EF Core vs Dapper (perf-test): +1.1%. Bun vs Deno (minimal): +2.5%. Once deployment and pools are equalized, the driver and the runtime decide; the framework layer above them is noise at this workload.</li><li><strong>Swoole is the efficiency phenomenon</strong>: 14 gold medals — every heavy perf-test combination — on the smallest memory footprint of the entire field (44 MB peak).</li></ol><h2 id="winners-by-category" tabindex="-1">Winners by category <a class="header-anchor" href="#winners-by-category" aria-label="Permalink to &quot;Winners by category&quot;">​</a></h2><p>Reference combos per scenario; medals count across <em>all</em> 38 combinations follows.</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Category</th><th>🥇</th><th>🥈</th><th>🥉</th></tr></thead><tbody><tr><td>Minimal baseline (100 VU)</td><td>Go 16,882</td><td>Deno 16,436</td><td>Fastify 16,243</td></tr><tr><td>perf-test (100 VU, 1 rec)</td><td>FastAPI 5,109</td><td>NpgsqlRest Files AOT 3,524</td><td>NpgsqlRest Files JIT 3,467</td></tr><tr><td>perf-test heavy (100 VU, 500 rec)</td><td>Swoole 45</td><td>Go 39</td><td>FastAPI 38</td></tr><tr><td>POST body (50 VU, 10 rec)</td><td>Go 7,598</td><td>Bun 7,461</td><td>Deno 7,238</td></tr><tr><td>Nested JSON (50 VU, d1)</td><td>Go 2,106</td><td>Swoole 2,092</td><td>FastAPI 2,030</td></tr><tr><td>Large payload (25 VU, 100 KB)</td><td>Go 1,427</td><td>Deno 1,418</td><td>FastAPI 1,416</td></tr><tr><td>Many params (50 VU)</td><td>Go 15,449</td><td>Bun 15,156</td><td>Deno 14,797</td></tr></tbody></table></div></div><p><strong>Podium totals across all 38 combinations:</strong></p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Service</th><th style="text-align:right;">🥇</th><th style="text-align:right;">🥈</th><th style="text-align:right;">🥉</th></tr></thead><tbody><tr><td>Go 1.26</td><td style="text-align:right;">17</td><td style="text-align:right;">13</td><td style="text-align:right;">3</td></tr><tr><td>Swoole PHP 6.2.1</td><td style="text-align:right;">14</td><td style="text-align:right;">8</td><td style="text-align:right;">0</td></tr><tr><td>FastAPI 0.139.0</td><td style="text-align:right;">4</td><td style="text-align:right;">3</td><td style="text-align:right;">16</td></tr><tr><td>Deno 2.9.2</td><td style="text-align:right;">2</td><td style="text-align:right;">3</td><td style="text-align:right;">6</td></tr><tr><td>Bun 1.3.14</td><td style="text-align:right;">1</td><td style="text-align:right;">5</td><td style="text-align:right;">6</td></tr><tr><td>NpgsqlRest SQL Files (AOT/JIT)</td><td style="text-align:right;">0</td><td style="text-align:right;">5</td><td style="text-align:right;">5</td></tr></tbody></table></div></div><p>Two services own 31 of 38 golds — but in disjoint territories. Go rules everything server-bound; Swoole rules everything payload-bound. They are almost never in each other&#39;s way.</p><h2 id="the-headline-ranking-with-tiers" tabindex="-1">The headline ranking, with tiers <a class="header-anchor" href="#the-headline-ranking-with-tiers" aria-label="Permalink to &quot;The headline ranking, with tiers&quot;">​</a></h2><p>perf-test at 100 VU, 1 record — the closest thing to &quot;a typical API lookup under load&quot;:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Tier</th><th>Service</th><th style="text-align:right;">req/s</th></tr></thead><tbody><tr><td><strong>Leader</strong></td><td>FastAPI</td><td style="text-align:right;">5,109</td></tr><tr><td><strong>Chasers</strong></td><td>NpgsqlRest SQL Files AOT / JIT</td><td style="text-align:right;">3,524 / 3,467</td></tr><tr><td><strong>The pack</strong> (within 20%)</td><td>Deno · Bun · Go · Spring Boot · NpgsqlRest Routine ×4 · Fastify · Express · Swoole</td><td style="text-align:right;">3,047 – 2,431</td></tr><tr><td><strong>Trailing</strong></td><td>Axum · .NET Dapper · Actix · .NET EF</td><td style="text-align:right;">2,263 – 2,230</td></tr><tr><td><strong>Bottom</strong></td><td>Django · PostgREST</td><td style="text-align:right;">1,911 / 1,322</td></tr></tbody></table></div></div><p>Three observations a ranking alone hides:</p><ul><li>The <strong>pack is dense</strong>: positions 4 through 14 span 25%. Small implementation choices (driver pipelining, JSON pass-through) matter more than language here.</li><li>The <strong>Rust pair trailing</strong> Go, Bun and even Spring Boot will surprise readers — but at 1-record requests this is a driver round-trip benchmark, and tokio-postgres&#39;s path through this workload is simply slower than pgx&#39;s or Npgsql&#39;s. The <a href="/blog/benchmarks-2026-07/actix.html">Actix</a> and <a href="/blog/benchmarks-2026-07/axum.html">Axum</a> pages dig in, including their remarkable CPU efficiency (the lowest in the field — they do these numbers half-asleep).</li><li><strong>PostgREST last</strong> despite this round <em>fixing</em> its connection pool handicap — see <a href="/blog/benchmarks-2026-07/postgrest.html">its page</a> for the honest breakdown.</li></ul><h2 id="scaling-behavior" tabindex="-1">Scaling behavior <a class="header-anchor" href="#scaling-behavior" aria-label="Permalink to &quot;Scaling behavior&quot;">​</a></h2><p>Requests/s at 1 record as concurrency grows, with the 1→200 VU multiplier:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Service</th><th style="text-align:right;">1 VU</th><th style="text-align:right;">50 VU</th><th style="text-align:right;">100 VU</th><th style="text-align:right;">200 VU</th><th style="text-align:right;">Factor</th></tr></thead><tbody><tr><td>FastAPI</td><td style="text-align:right;">854</td><td style="text-align:right;">5,048</td><td style="text-align:right;">5,109</td><td style="text-align:right;">5,053</td><td style="text-align:right;"><strong>6.0×</strong></td></tr><tr><td>NpgsqlRest Files AOT</td><td style="text-align:right;">658</td><td style="text-align:right;">3,568</td><td style="text-align:right;">3,524</td><td style="text-align:right;">3,481</td><td style="text-align:right;"><strong>5.4×</strong></td></tr><tr><td>NpgsqlRest Files JIT</td><td style="text-align:right;">753</td><td style="text-align:right;">3,621</td><td style="text-align:right;">3,467</td><td style="text-align:right;">3,453</td><td style="text-align:right;"><strong>4.8×</strong></td></tr><tr><td>Deno</td><td style="text-align:right;">676</td><td style="text-align:right;">3,065</td><td style="text-align:right;">3,047</td><td style="text-align:right;">3,120</td><td style="text-align:right;"><strong>4.6×</strong></td></tr><tr><td>Bun</td><td style="text-align:right;">738</td><td style="text-align:right;">3,068</td><td style="text-align:right;">3,016</td><td style="text-align:right;">3,140</td><td style="text-align:right;"><strong>4.3×</strong></td></tr><tr><td>Go</td><td style="text-align:right;">927</td><td style="text-align:right;">3,049</td><td style="text-align:right;">2,948</td><td style="text-align:right;">2,943</td><td style="text-align:right;"><strong>3.3×</strong></td></tr></tbody></table></div></div><p>Two patterns. First, <strong>everyone saturates by 50 VU</strong> and holds flat to 200 — no service in the field degrades under 4× more concurrency than its saturation point, which is a collective compliment to 2026&#39;s server runtimes. Second, the scaling factor mostly measures the <em>inverse</em> of single-request speed: Go&#39;s &quot;low&quot; 3.3× reflects the field&#39;s best 1 VU baseline (927), not a scaling problem.</p><h2 id="latency-the-p99-story" tabindex="-1">Latency: the p99 story <a class="header-anchor" href="#latency-the-p99-story" aria-label="Permalink to &quot;Latency: the p99 story&quot;">​</a></h2><p>All 760 tests recorded full latency distributions (median/p90/p95/p99/max — in the <a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">dataset</a>). The benchmark&#39;s latency objective was p99 &lt; 1 s per test. Results:</p><ul><li><strong>657 of 760 tests met it.</strong> The 103 that did not are <em>the same combinations for every service</em>: 100+ records at 50+ VU — where a 100-record, 23-column JSON response at 200 concurrent users is simply more bytes than 4 cores serialize in under a second at p99. Physics, not framework failures.</li><li>Held per service: 11 of 16 perf-test combinations for eighteen services; <strong>Bun and Swoole held 12</strong> — the only two to keep p99 under 1 s at 50 VU × 500 records.</li><li>At sane payloads the field is tight: on minimal at 100 VU, every service&#39;s p99 sits between 21 ms (Go) and 43 ms except Django and PostgREST.</li><li><strong>Zero failed requests, anywhere.</strong> 20-for-20 services survived every load level without a single 5xx or dropped connection — the <code>restart: unless-stopped</code> safety nets went unused.</li></ul><h2 id="resource-efficiency" tabindex="-1">Resource efficiency <a class="header-anchor" href="#resource-efficiency" aria-label="Permalink to &quot;Resource efficiency&quot;">​</a></h2><p>Peak/average memory and CPU, measured only during each service&#39;s active test windows:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Service</th><th style="text-align:right;">Peak MB</th><th style="text-align:right;">Avg MB</th><th style="text-align:right;">Avg CPU</th></tr></thead><tbody><tr><td>Swoole PHP</td><td style="text-align:right;">44</td><td style="text-align:right;">24</td><td style="text-align:right;">66%</td></tr><tr><td>Go</td><td style="text-align:right;">59</td><td style="text-align:right;">25</td><td style="text-align:right;">90%</td></tr><tr><td>PostgREST</td><td style="text-align:right;">112</td><td style="text-align:right;">57</td><td style="text-align:right;">103%</td></tr><tr><td>Axum</td><td style="text-align:right;">145</td><td style="text-align:right;">25</td><td style="text-align:right;"><strong>49%</strong></td></tr><tr><td>NpgsqlRest AOT (best of 3)</td><td style="text-align:right;">155</td><td style="text-align:right;">62</td><td style="text-align:right;">110%</td></tr><tr><td>Actix-web</td><td style="text-align:right;">167</td><td style="text-align:right;">59</td><td style="text-align:right;"><strong>58%</strong></td></tr><tr><td>.NET 10 EF</td><td style="text-align:right;">214</td><td style="text-align:right;">124</td><td style="text-align:right;">150%</td></tr><tr><td>NpgsqlRest JIT (best of 3)</td><td style="text-align:right;">225</td><td style="text-align:right;">124</td><td style="text-align:right;">129%</td></tr><tr><td>.NET 10 Dapper</td><td style="text-align:right;">244</td><td style="text-align:right;">102</td><td style="text-align:right;">128%</td></tr><tr><td>FastAPI</td><td style="text-align:right;">282</td><td style="text-align:right;">237</td><td style="text-align:right;"><strong>200%</strong></td></tr><tr><td>Bun</td><td style="text-align:right;">340</td><td style="text-align:right;">229</td><td style="text-align:right;">110%</td></tr><tr><td>Django</td><td style="text-align:right;">671</td><td style="text-align:right;">281</td><td style="text-align:right;"><strong>230%</strong></td></tr><tr><td>Deno</td><td style="text-align:right;">740</td><td style="text-align:right;">500</td><td style="text-align:right;">105%</td></tr><tr><td>Spring Boot</td><td style="text-align:right;">756</td><td style="text-align:right;">404</td><td style="text-align:right;">98%</td></tr><tr><td>Express (8 workers)</td><td style="text-align:right;">1,094</td><td style="text-align:right;">577</td><td style="text-align:right;">109%</td></tr><tr><td>Fastify (8 workers)</td><td style="text-align:right;">1,177</td><td style="text-align:right;">600</td><td style="text-align:right;">92%</td></tr></tbody></table></div></div><p>The fairness overhaul&#39;s price tag is visible here: <strong>equal cores cost the interpreted runtimes their memory story</strong>. Eight Node processes cost Fastify and Express over a gigabyte at peak; FastAPI&#39;s crown came with the field&#39;s second-highest CPU burn. Meanwhile Swoole delivers 14 golds from 44 MB, and the Rust pair posts mid-table throughput at <em>half the CPU of anyone else</em> — the two most efficient architectures in the field by throughput-per-resource, one interpreted, one compiled.</p><p>Bun deserves a line: 340 MB for 8 processes versus Deno&#39;s 740 MB and Node&#39;s ~1,100 MB for the same work is the clearest runtime-efficiency signal in the JavaScript quartet.</p><h2 id="performance-per-line-of-code" tabindex="-1">Performance per line of code <a class="header-anchor" href="#performance-per-line-of-code" aria-label="Permalink to &quot;Performance per line of code&quot;">​</a></h2><p>Lines of application code (or configuration, where no code exists) to implement the identical six endpoints, against headline throughput:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Service</th><th style="text-align:right;">Lines</th><th style="text-align:right;">perf-test 100 VU/1 rec</th></tr></thead><tbody><tr><td>PostgREST</td><td style="text-align:right;"><strong>12</strong> (config)</td><td style="text-align:right;">1,322</td></tr><tr><td>NpgsqlRest Routine</td><td style="text-align:right;"><strong>21</strong> (config)</td><td style="text-align:right;">2,617</td></tr><tr><td>Fastify / Express</td><td style="text-align:right;">102 / 103</td><td style="text-align:right;">2,583 / 2,578</td></tr><tr><td>.NET EF / FastAPI / Dapper</td><td style="text-align:right;">105 / 123 / 129</td><td style="text-align:right;">2,230 / 5,109 / 2,255</td></tr><tr><td>NpgsqlRest SQL Files</td><td style="text-align:right;"><strong>140</strong> (config + the SQL itself)</td><td style="text-align:right;">3,467–3,524</td></tr><tr><td>Bun / Deno</td><td style="text-align:right;">140 / 143</td><td style="text-align:right;">3,016 / 3,047</td></tr><tr><td>Spring Boot / Django / Swoole</td><td style="text-align:right;">165 / 183 / 198</td><td style="text-align:right;">2,710 / 1,911 / 2,431</td></tr><tr><td>Axum / Actix / Go</td><td style="text-align:right;">248 / 256 / 303</td><td style="text-align:right;">2,263 / 2,246 / 2,948</td></tr></tbody></table></div></div><p>The pattern from January holds and sharpens: <strong>the top of the throughput chart and the bottom of the effort chart are the same neighborhood.</strong> NpgsqlRest&#39;s 21-line configuration outruns Go&#39;s 303 hand-written lines on this scenario; its SQL-file variant — where the only &quot;code&quot; is the SQL you&#39;d write anyway — sits #2 in the entire field. Go remains the honest counter-example: when you <em>do</em> pay the 303 lines, you buy categories nothing else wins.</p><h2 id="january-→-july-ranking-movements" tabindex="-1">January → July: ranking movements <a class="header-anchor" href="#january-→-july-ranking-movements" aria-label="Permalink to &quot;January → July: ranking movements&quot;">​</a></h2><p>Absolute numbers are not comparable across rounds (see <a href="/blog/benchmarks-2026-07/">methodology</a>); positions are:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Service</th><th>January</th><th>July</th><th>Why</th></tr></thead><tbody><tr><td>FastAPI</td><td>Bottom tier</td><td><strong>#1 perf-test</strong></td><td>workers 1 → 8</td></tr><tr><td>Swoole</td><td>Large-payload champion</td><td>Mid-pack on large, still heavy-perf-test king</td><td>workers cpu×2 → cpu</td></tr><tr><td>NpgsqlRest</td><td>#1 perf-test (routine)</td><td>#2–3 (SQL files)</td><td>New source; FastAPI&#39;s fix outpaced it</td></tr><tr><td>Bun</td><td>&quot;Single-threaded champion&quot;</td><td>Pack member</td><td>Everyone got workers</td></tr><tr><td>PostgREST</td><td>Bottom tier</td><td>Bottom tier</td><td>Pool fix helped less than hoped</td></tr><tr><td>Go</td><td>Minimal/params/POST king</td><td>Unchanged</td><td>Never depended on configuration</td></tr></tbody></table></div></div><p>The honest summary: <strong>about half of January&#39;s ranking signal was deployment configuration, not framework capability.</strong> This round removed that variable. What remains — driver efficiency, serialization architecture, runtime memory models — is what these pages analyze.</p><h2 id="limitations-stated-plainly" tabindex="-1">Limitations, stated plainly <a class="header-anchor" href="#limitations-stated-plainly" aria-label="Permalink to &quot;Limitations, stated plainly&quot;">​</a></h2><ul><li>One run per combination; no variance bars. The 30-second quiet gaps, per-test warmups, and paused-idle isolation minimize drift, but a delta under ~3% between adjacent services should be read as a tie.</li><li>4 dedicated cores per service. Rankings could shift at 16+ cores, particularly for the JVM.</li><li>Closed-loop load (k6 VUs) measures max throughput well but understates latency under a fixed arrival rate; an open-model scenario is on the wishlist for next round.</li><li>The workload is deliberately database-shaped (function call in, JSON out). CPU-bound application logic would favor the compiled languages far more than these tables do.</li></ul><hr><p><strong>Series:</strong> <a href="/blog/benchmarks-2026-07/">Introduction</a> · <a href="/blog/benchmarks-2026-07/npgsqlrest.html">NpgsqlRest Deep Dive</a> · <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a></p><p><strong>Next:</strong> <a href="/blog/benchmarks-2026-07/results.html">Raw Results →</a></p>',41)]))}const p=e(s,[["render",n]]);export{y as __pageData,p as default};
